function encrypt($data, $key = 'your_fixed_key_here') {
    $encryptedData = '';
    for ($i = 0; $i < strlen($data); $i++) {
        $char = $data[$i];
        $keyChar = $key[$i % strlen($key)];
        $encryptedChar = chr(ord($char) ^ ord($keyChar));
        $encryptedData .= $encryptedChar;
    }
    return base64_encode($encryptedData);
}

function decrypt($data, $key = 'your_fixed_key_here') {
    $encryptedData = base64_decode($data);
    $decryptedData = '';
    for ($i = 0; $i < strlen($encryptedData); $i++) {
        $char = $encryptedData[$i];
        $keyChar = $key[$i % strlen($key)];
        $decryptedChar = chr(ord($char) ^ ord($keyChar));
        $decryptedData .= $decryptedChar;
    }
    return $decryptedData;
}

